from pyparsing import CharsNotIn
from pyparsing import Literal as L
from pyparsing import OneOrMore
from pyparsing import Optional
from pyparsing import Regex
from pyparsing import SkipTo
from pyparsing import White
from pyparsing import Word
from pyparsing import ZeroOrMore
from pyparsing import alphanums
from pyparsing import alphas
from pyparsing import hexnums
from pyparsing import nums

from piglet import parse

# https://infra.spec.whatwg.org/#noncharacter
html5_non_chars = (
    "\U0000fdd0"
    "\U0000fdd1"
    "\U0000fdd2"
    "\U0000fdd3"
    "\U0000fdd4"
    "\U0000fdd5"
    "\U0000fdd6"
    "\U0000fdd7"
    "\U0000fdd8"
    "\U0000fdd9"
    "\U0000fdda"
    "\U0000fddb"
    "\U0000fddc"
    "\U0000fddd"
    "\U0000fdde"
    "\U0000fddf"
    "\U0000fffe"
    "\U0000ffff"
    "\U0001fffe"
    "\U0001ffff"
    "\U0002fffe"
    "\U0002ffff"
    "\U0003fffe"
    "\U0003ffff"
    "\U0004fffe"
    "\U0004ffff"
    "\U0005fffe"
    "\U0005ffff"
    "\U0006fffe"
    "\U0006ffff"
    "\U0007fffe"
    "\U0007ffff"
    "\U0008fffe"
    "\U0008ffff"
    "\U0009fffe"
    "\U0009ffff"
    "\U000afffe"
    "\U000affff"
    "\U000bfffe"
    "\U000bffff"
    "\U000cfffe"
    "\U000cffff"
    "\U000dfffe"
    "\U000dffff"
    "\U000efffe"
    "\U000effff"
    "\U000ffffe"
    "\U000fffff"
    "\U0010fffe"
    "\U0010ffff"
)

# https://html.spec.whatwg.org/multipage/syntax.html#attributes-2
attribute_name = Regex(f"[^ \"'>/=\u0000-\u001f\u007f-\u009f{html5_non_chars}]+")
# Spec does not specify which characters are valid in tag names, other than
# to say that 'HTML elements all have names that only use ASCII alphanumerics'
tag_name = Word(alphanums, alphanums + "-")
qname = (
    (ZeroOrMore(tag_name + ":") + tag_name)
    .set_name("qname")
    .set_results_name("qname")
    .set_parse_action("".join)
)

quoted_string = (
    L('"').set_results_name("qsquote") + SkipTo('"').set_results_name("qscontent") + '"'
) | (
    L("'").set_results_name("qsquote") + SkipTo("'").set_results_name("qscontent") + "'"
)

attribute = (
    attribute_name().set_results_name("name")
    + Optional(White()).set_results_name("space1")
    + Optional("=" + Optional(White()).set_results_name("space2") + quoted_string())
    + Optional(White()).set_results_name("space3")
).set_parse_action(
    lambda ts: (
        ts.name,
        parse.Attribute(
            name=ts.name,
            quote=ts.qsquote,
            value=ts.get("qscontent"),
            space1=ts.space1,
            space2=ts.space2,
            space3=ts.space3,
        ),
    )
)

open_tag = (
    "<"
    + qname
    + Optional(
        White().set_results_name("space")
        + ZeroOrMore(attribute).set_results_name("attrs")
    )
    + ">"
).set_parse_action(
    lambda ts: parse.OpenTag(qname=ts.qname, space=ts.space, attrs=list(ts.attrs))
)

close_tag = "</" + qname + ">"
close_tag.set_parse_action(lambda ts: parse.CloseTag(qname=ts.qname))

text = OneOrMore(CharsNotIn("<&"))
text.set_parse_action(lambda ts: parse.Text(content=ts[0]))

cdata_open_tag = (
    "<"
    + (L("script") | L("style")).set_results_name("tagname")
    + Optional(
        White().set_results_name("space")
        + ZeroOrMore(attribute).set_results_name("attrs")
    )
    + ">"
).set_parse_action(
    lambda ts: parse.OpenTag(qname=ts.tagname, space=ts.space, attrs=list(ts.attrs))
)

cdata_close_tag = (
    "</" + (L("script") | L("style")).set_results_name("tagname") + ">"
).set_parse_action(lambda ts: parse.CloseTag(qname=ts.tagname))

open_close_tag = (
    L("<")
    + qname().set_results_name("qname")
    + Optional(White()).set_results_name("space")
    + ZeroOrMore(attribute).set_results_name("attrs")
    + "/>"
).set_parse_action(
    lambda ts: parse.OpenCloseTag(qname=ts.qname, space=ts.space, attrs=list(ts.attrs))
)

implicit_cdata = (
    cdata_open_tag().set_results_name("opentag")
    + SkipTo(cdata_close_tag).set_results_name("content")
    + cdata_close_tag().set_results_name("closetag")
).set_parse_action(
    lambda ts: [ts.opentag, parse.Text(content=ts.content, cdata=True), ts.closetag]
)

alpha_entity = (L("&") + Word(alphas) + L(";")).set_parse_action("".join)
numeric_entity = (L("&#") + Word(nums) + L(";")).set_parse_action("".join)
hex_entity = (L("&#x") + Word(hexnums) + L(";")).set_parse_action("".join)
entity = (
    (alpha_entity | hex_entity | numeric_entity)
    .set_parse_action("".join)
    .set_results_name("reference")
    .set_parse_action(lambda ts: parse.Entity(reference="".join(ts.reference)))
)

comment = (
    L("<!--") + SkipTo("-->").set_results_name("content") + L("-->")
).set_parse_action(lambda ts: parse.Comment(**ts))

cdata = (
    L("<![CDATA[") + SkipTo("]]>").set_results_name("content") + L("]]>")
).set_parse_action(lambda ts: parse.CDATA(**ts))

declaration = (
    L("<!") + SkipTo(">").set_results_name("content") + L(">")
).set_parse_action(lambda ts: parse.Declaration(**ts))

processing_instruction = (
    L("<?")
    + Word(alphanums).set_results_name("target")
    + (White() + SkipTo("?>")).set_results_name("content").set_parse_action("".join)
    + L("?>")
).set_parse_action(lambda ts: parse.PI(**ts))

html = ZeroOrMore(
    text
    | implicit_cdata
    | open_tag
    | close_tag
    | open_close_tag
    | entity
    | comment
    | cdata
    | declaration
    | processing_instruction
)
html_template_parser = html()
html_template_parser.leave_whitespace()
html_template_parser.parse_with_tabs()
